query:
-- 修正 epic 捕捉率（25% → 10%）
UPDATE game_monster_catalog SET base_capture_rate = 10 WHERE rarity = 'epic';

-- legendary 魔物設為不可捕捉（傳說級不應被捕捉）
UPDATE game_monster_catalog SET is_capturable = 0, base_capture_rate = 0 WHERE rarity = 'legendary';

-- 確認修正結果
SELECT rarity, COUNT(*) as cnt, AVG(base_capture_rate) as avg_rate, SUM(CASE WHEN is_capturable = 1 THEN 1 ELSE 0 END) as capturable_cnt
FROM game_monster_catalog
GROUP BY rarity
ORDER BY cnt DESC;

